<new_content>import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';

function App() {
  const [activeView, setActiveView] = useState('dashboard');
  const [alerts, setAlerts] = useState([]);

  // Simulate new security alerts
  useEffect(() => {
    const alertTypes = [
      { 
        severity: 'critical', 
        message: 'Multiple failed login attempts detected', 
        source: '192.168.1.45' 
      },
      { 
        severity: 'high', 
        message: 'Possible SQL injection attempt', 
        source: '45.232.121.56' 
      },
      { 
        severity: 'medium', 
        message: 'Unusual authentication pattern', 
        source: '10.0.0.32' 
      },
      { 
        severity: 'low', 
        message: 'Excessive file access attempts', 
        source: '192.168.1.76' 
      }
    ];

    const interval = setInterval(() => {
      // Random chance to create a new alert
      if (Math.random() > 0.7) {
        const randomAlert = alertTypes[Math.floor(Math.random() * alertTypes.length)];
        const newAlert = {
          id: Date.now(),
          ...randomAlert,
          time: new Date().toLocaleTimeString(),
          status: 'active'
        };

        setAlerts(prevAlerts => [newAlert, ...prevAlerts.slice(0, 19)]); // Keep last 20 alerts
      }
    }, 20000);

    return () => clearInterval(interval);
  }, []);

  // Handle view changes from sidebar
  const handleViewChange = (view) => {
    setActiveView(view);
  };

  // Render content based on active view
  const renderContent = () => {
    switch(activeView) {
      case 'dashboard':
        return <Dashboard alerts={alerts} />;
      case 'alerts':
        return <div className="p-6">
          <h1 className="text-2xl font-bold text-white mb-6">Security Alerts</h1>
          <div className="bg-dark-200 rounded-lg border border-gray-700 overflow-hidden">
            <div className="p-4">
              <h2 className="text-lg font-semibold text-white mb-4">Recent Alerts</h2>
              <table className="w-full">
                <thead className="bg-dark-100">
                  <tr>
                    <th className="px-4 py-2 text-left text-sm font-medium text-gray-300">Severity</th>
                    <th className="px-4 py-2 text-left text-sm font-medium text-gray-300">Message</th>
                    <th className="px-4 py-2 text-left text-sm font-medium text-gray-300">Source</th>
                    <th className="px-4 py-2 text-left text-sm font-medium text-gray-300">Time</th>
                    <th className="px-4 py-2 text-left text-sm font-medium text-gray-300">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-700">
                  {alerts.length > 0 ? alerts.map(alert => (
                    <tr key={alert.id} className="hover:bg-dark-100">
                      <td className="px-4 py-3">
                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                          ${alert.severity === 'critical' ? 'bg-alert-high/20 text-alert-high' : 
                          alert.severity === 'high' ? 'bg-alert-high/10 text-alert-high' :
                          alert.severity === 'medium' ? 'bg-alert-medium/20 text-alert-medium' :
                          'bg-alert-low/20 text-alert-low'}`}>
                          {alert.severity}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-sm text-white">{alert.message}</td>
                      <td className="px-4 py-3 text-sm text-gray-300">{alert.source}</td>
                      <td className="px-4 py-3 text-sm text-gray-300">{alert.time}</td>
                      <td className="px-4 py-3">
                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                          ${alert.status === 'active' ? 'bg-blue-100/10 text-blue-400' : 'bg-gray-100/10 text-gray-400'}`}>
                          {alert.status}
                        </span>
                      </td>
                    </tr>
                  )) : (
                    <tr>
                      <td colSpan="5" className="px-4 py-3 text-sm text-gray-400 text-center">No alerts to display</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>;
      case 'rules':
        return <div className="p-6">
          <h1 className="text-2xl font-bold text-white mb-6">Security Rules</h1>
          <p className="text-gray-300 mb-4">Configure and manage detection rules for the IDS system.</p>
          {/* Rules content would go here */}
        </div>;
      default:
        return <div className="p-6">
          <h1 className="text-2xl font-bold text-white mb-4">{activeView.replace('-', ' ').replace(/\b\w/g, l => l.toUpperCase())}</h1>
          <p className="text-gray-300">This section is under development.</p>
        </div>;
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-dark-300 text-white">
      <Header />
